import { type DependencyList, type SetStateAction, useRef } from 'react';
import { type ControlProps, type ControlValue, useControl } from '#registry/default/hooks/use-control.ts';
import { useStableCallback } from '#registry/default/hooks/use-stable-callback.ts';

type PendingControlProps<T extends ControlValue = ControlValue, TCtx = void> = ControlProps<T, TCtx> & {
  skipPending?: boolean;
};

export function usePendingControl<T extends ControlValue, TCtx = void>({
  value,
  defaultValue,
  finalValue,
  deps,
  onChange,
  skipPending = false,
}: PendingControlProps<T, TCtx>) {
  deps = [value, ...(deps || [])] as DependencyList;
  const [pendingValue, setPendingValue] = useControl<T, TCtx>({
    defaultValue: typeof value === 'undefined' ? defaultValue : value,
    finalValue,
    deps,
  });

  const isPending = useRef(false);

  const submit = useStableCallback((val?: SetStateAction<T>, ctx?: TCtx) => {
    if (!isPending.current && typeof val === 'undefined') return;
    isPending.current = false;
    onChange?.(typeof val === 'undefined' ? pendingValue : val, ctx);
  });

  const reset = useStableCallback((ctx?: TCtx) => {
    isPending.current = false;
    setPendingValue(
      typeof value === 'undefined' ? (typeof defaultValue === 'undefined' ? finalValue! : defaultValue) : value,
      ctx
    );
  });

  const handleChange = useStableCallback((val: SetStateAction<T>, ctx?: TCtx) => {
    if (skipPending) return submit(val, ctx);
    isPending.current = true;
    setPendingValue(val, ctx);
  });

  return [pendingValue, handleChange, { submit, reset }] as const;
}
